tool_calls:
mkdir -p /release

# Parse commits.log, group by type, and generate CHANGELOG.md
awk -F'[():]' '
{
    type  = $1
    scope = $2
    # message: everything after "type(scope): ", strip leading space
    msg = $0
    sub(/^[^:]*\([^)]*\): /, "", msg)

    if (type == "feat") {
        feat[feat_n++] = scope ": " msg
    } else if (type == "fix") {
        fix[fix_n++] = scope ": " msg
    } else {
        other[other_n++] = scope ": " msg
    }
}
END {
    print "# Changelog"
    print ""

    print "## Features"
    for (i = 0; i < feat_n; i++) print "- " feat[i]
    print ""

    print "## Bug Fixes"
    for (i = 0; i < fix_n; i++) print "- " fix[i]
    print ""

    print "## Other"
    for (i = 0; i < other_n; i++) print "- " other[i]
}
' /data/commits.log > /release/CHANGELOG.md

cat /release/CHANGELOG.md

